
import React, { useState, useEffect } from "react";



import { CloseModal, OpenModal } from "../../../components/DialogHRM";
import {  SvgIcon_Cmpt, TextInput_Cmpt, SearchInput_Cmpt } from "../../../components";
import { updStore, getStore, gen16CodeId, ObjectKeys, parseDateMMYYYY, qryKClient, parseDate, parseDateMMDDYYYY, txtOrempty, compareJSON, fetchEncryptStream, _monthNames } from "../../../stores/Utils";

import DateCalComponent from "./DateCalComponent";
import { generateTranslateDriverLicense } from "../services/print_service";



